const request = $('Inspect Refund Sent Webhook').first()?.json ?? $('When clicking \'Execute workflow\'').first()?.json ?? $input.first()?.json ?? {};
const query = request.query ?? request;
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const parseIntSafe = (value, fallback) => {
  const parsed = Number.parseInt(clean(value), 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
};
return [{ json: { gmail_query: clean(query.q) || 'in:sent to:treasury.avondaleltc@gmail.com', gmail_limit: Math.min(parseIntSafe(query.limit, 25), 100) } }];

const decodeHtml = (value) => {
  if (!value) return '';
  return String(value)
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&pound;/gi, '\u00A3')
    .replace(/&#163;/gi, '\u00A3')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
};
const htmlToText = (html) => {
  if (!html) return '';
  return decodeHtml(
    String(html)
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<\/p>/gi, '\n')
      .replace(/<\/div>/gi, '\n')
      .replace(/<\/li>/gi, '\n')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\r/g, '')
      .replace(/[ \t]+\n/g, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim(),
  );
};
return [{ json: { messages: $input.all().map((item) => {
  const json = item.json ?? {};
  const headers = json.headers ?? json.email?.headers ?? {};
  const metadata = json.metadata ?? json.email?.metadata ?? {};
  const textHtml = json.textHtml ?? json.html ?? json.textAsHtml ?? json.bodyHtml ?? '';
  const textPlain = json.textPlain ?? json.text ?? json.bodyText ?? '';
  const normalizedText = textPlain && textPlain.trim() ? decodeHtml(textPlain) : htmlToText(textHtml);
  return {
    id: json.id ?? null,
    message_id: json.messageId ?? json.message_id ?? headers['message-id'] ?? headers.messageId ?? metadata['message-id'] ?? metadata.messageId ?? null,
    subject: json.subject ?? headers.subject ?? metadata.subject ?? null,
    sent_date: json.date ?? json.sentDate ?? json.sent_date ?? headers.sent_date ?? headers.date ?? metadata.date ?? null,
    preview: normalizedText.slice(0, 800),
  };
}) } }];
